def build_cai_dataset(
    model, prompts: list, constitution: list, n_rounds: int = 1
) -> list:
    """Build preference pairs for SFT using constitutional self-critique."""
    pairs = []
    for prompt in prompts:
        initial = model.generate(prompt, temperature=0.8)
        revised = self_critique_revise(
            model, prompt, initial, constitution, n_rounds
        )
        # Skip if revision is identical to initial
        if revised.strip() == initial.strip():
            continue
        pairs.append({
            "prompt": prompt,
            "chosen": revised,   # revised = preferred
            "rejected": initial, # initial = dispreferred
        })
    return pairs

def optimal_n_rounds(
    model, prompt: str, constitution: list, max_rounds: int = 5
) -> tuple[str, int]:
    """Run critique-revise until critique says no issues found."""
    import random
    current = model.generate(prompt, temperature=0.8)
    for round_idx in range(max_rounds):
        principle = random.choice(constitution)
        critique = model.generate(
            CRITIQUE_PROMPT.format(
                original_prompt=prompt,
                initial_response=current,
                principle=principle,
            )
        )
        # Early stop if no issues identified
        if "no issues" in critique.lower() or "does not violate" in critique.lower():
            return current, round_idx
        current = model.generate(
            REVISION_PROMPT.format(
                original_prompt=prompt,
                initial_response=current,
                critique=critique,
            )
        )
    return current, max_rounds
